        leads_extra += add_small('D_S05',0.00018,0.08,0.24,0.35)
        # New enterprise leads after day140; few close inside short horizons.
        lam=max(0,active_s2*0.00015*rel_sat)
        for _ in range(max(0,int(random.gauss(lam,max(1,math.sqrt(max(1,lam))))))):
