                else:
                    e['seats']=0
            e['age']+=1
        ents=[e for e in ents if e['seats']>0]
        # costs - Week21 support surge and D_S07 ad scale, then planned taper as stale tickets clear.
        if rel<=7: ops=296500.0
        elif rel<=28: ops=245000.0
